package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.*; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="resume_document") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ResumeDocument extends AuditedSoftDeletableEntity { @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="media_asset_id",nullable=false) private MediaAsset mediaAsset; @Enumerated(EnumType.STRING) @Column(nullable=false) private ContentStatus status; @Column(name="published_at") private Instant publishedAt; private ResumeDocument(UUID id,LanguageCode language,MediaAsset media,Instant at){initialize(id,at);languageCode=java.util.Objects.requireNonNull(language,"language");mediaAsset=java.util.Objects.requireNonNull(media,"media");status=ContentStatus.DRAFT;} public static ResumeDocument create(UUID id,LanguageCode language,MediaAsset media,Instant at){return new ResumeDocument(id,language,media,at);} public void update(MediaAsset media,Instant at){mediaAsset=java.util.Objects.requireNonNull(media,"media");updatedAt=java.util.Objects.requireNonNull(at,"at");} public void publish(Instant at){if(status!=ContentStatus.DRAFT)throw new IllegalStateException("Only drafts can be published");status=ContentStatus.PUBLISHED;publishedAt=java.util.Objects.requireNonNull(at,"at");updatedAt=at;} public void archive(Instant at){if(status!=ContentStatus.PUBLISHED)throw new IllegalStateException("Only published documents can be archived");status=ContentStatus.ARCHIVED;updatedAt=java.util.Objects.requireNonNull(at,"at");} }
